import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CircularProgress, Tooltip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface RecentAlert {
  time: string;
  alertType: string;
  cameraId: string;
}

interface CameraStatus {
  id: string;
  status: string;
}

interface SecurityData {
  activeCameras: number;
  recentAlerts: RecentAlert[];
  cameraStatus: CameraStatus[];
}

export default function Widget() {
  const securityData = response.data as SecurityData;
  const { activeCameras, recentAlerts, cameraStatus } = securityData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2E2E2E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Active Cameras
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFFFFF' }}>
              {activeCameras}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Recent Alerts
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {recentAlerts.slice(0, 3).map((alert, index) => (
                <Tooltip key={index} title={`${alert.alertType} at ${alert.time}`}>
                  <Chip
                    label={`Cam ${alert.cameraId}`}
                    sx={{ fontSize: '11px', color: '#FFFFFF', bgcolor: '#FF0000', px: 1 }}
                  />
                </Tooltip>
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Camera Status
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {cameraStatus.slice(0, 5).map((camera) => (
                <Chip
                  key={camera.id}
                  label={camera.id}
                  sx={{
                    fontSize: '11px',
                    color: '#FFFFFF',
                    bgcolor: camera.status === 'Online' ? '#4CAF50' : '#FF5722',
                    px: 1,
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
